export interface PlatformReward {
    rewardPerView: string;
    minPayout: string;
    maxPayout: string;
    submissionLimit?: string;
    maxPayoutPerCreator?: string;
}

export interface FAQ {
    question: string;
    answer: string;
}

export interface ApplicationQuestion {
    id: string;
    text: string;
    type: "Text" | "Select" | "Multiple Choice";
    required: boolean;
}

export interface Campaign {
    id: string;
    name: string;
    description: string;
    type: "UGC" | "Clipping" | "Both";
    category: "Music" | "Personal Brand" | "Technology" | "Product" | "Entertainment" | "Logo" | "Slideshow" | "Other";
    thumbnail: string;
    budget: number;
    startDate: string;
    endDate: string;
    status: "Active" | "Pending" | "Ended" | "Paused" | "Draft";
    platforms: ("Instagram" | "Youtube")[];
    rewardPerView: string;
    minPayout: string;
    maxPayout: string;
    submissionLimit?: string;
    maxPayoutPerCreator?: string;
    usePerPlatformRewards: boolean;
    perPlatformRewards: Record<string, PlatformReward>;
    requirements: string[];
    contentLinks: string[];
    faqs: FAQ[];
    requireSpecificSounds: boolean;
    specificSounds?: Record<string, string>;
    requireApplication: boolean;
    applicationQuestions: ApplicationQuestion[];
    requireDemographics: boolean;
    showOnDiscover: boolean;
    selectedProductId: string;
    brandName?: string;
    objective?: string;
    approval: number;
    views: number;
    creators: number;
    paidOut: number; // Added to match the card design logic
}

